    // Show the sender a "waiting" progress indicator
    if (this.onTransferProgress) {
      this.onTransferProgress({
        id: targetSocketId + '_' + file.name,
        fileName: file.name,
        progress: 0,
        type: 'upload',
        status: 'waiting_for_accept',
        sentSize: 0,
        totalSize: file.size,
        totalChunks: Math.ceil(file.size / CHUNK_SIZE),
        processedChunks: 0,
        speedBytesPerSec: 0
      });
    }

    channel.send(JSON.stringify({
      type: 'file-offer',
      fileId,
      name: file.name,
      size: file.size
    }));

    console.log(`📤 Sent file offer: ${file.name} (${file.size} bytes) → ${targetSocketId}`);
  }

  _beginSendFile(channel, targetSocketId, file) {
    const meta = { type: 'file-meta', name: file.name, size: file.size, mime: file.type };
    channel.send(JSON.stringify(meta));

    channel.bufferedAmountLowThreshold = CHUNK_SIZE * 8;

    const fileReader = new FileReader();
    let offset = 0;
    let sentChunks = 0;
    const totalChunks = Math.ceil(file.size / CHUNK_SIZE);
    const startTime = Date.now();
    let lastProgressTime = startTime;

    const readSlice = (o) => {
      const slice = file.slice(o, o + CHUNK_SIZE);
      fileReader.readAsArrayBuffer(slice);
    };

    fileReader.onload = (e) => {
      channel.send(e.target.result);
      offset += e.target.result.byteLength;
      sentChunks++;

      const now = Date.now();
      const elapsed = (now - startTime) / 1000;
      const speedBytesPerSec = elapsed > 0 ? offset / elapsed : 0;
      const progress = Math.round((offset / file.size) * 100);

      if (now - lastProgressTime > 80 || offset >= file.size) {
        lastProgressTime = now;
        if (this.onTransferProgress) {
          this.onTransferProgress({
            id: targetSocketId + '_' + file.name,
            fileName: file.name,
            progress,
            type: 'upload',
            status: offset >= file.size ? 'complete' : 'sending',
            sentSize: offset,
            totalSize: file.size,
            totalChunks,
            processedChunks: sentChunks,
            speedBytesPerSec
          });
        }
      }

      if (offset < file.size) {
        if (channel.bufferedAmount > channel.bufferedAmountLowThreshold) {
          channel.onbufferedamountlow = () => {
            channel.onbufferedamountlow = null;
            readSlice(offset);
          };
        } else {
          readSlice(offset);
        }
      } else {
        console.log(`✅ File sent: ${file.name}`);
      }
    };

    fileReader.onerror = (e) => console.error('FileReader error:', e);

    readSlice(0);
  }

  sendGroupFile(targetSocketIds, file) {
    // Send an offer to each target independently
    targetSocketIds.forEach(targetId => {
      this.sendFile(targetId, file);
    });
  }

  disconnect() {
    this.connections.forEach(pc => pc.close());
    this.connections.clear();
    this.dataChannels.clear();
    this.pendingOutboundFiles.clear();
    this.socket.disconnect();
  }
}

export default WebRTCHandler;
